function newChaseDir(actor: Actor): void {
  if (!actor.target) {
    throw new Error('newChaseDir called with no target');
  }
  const oldDir = actor.moveDir;
  const turnAround = opposite[oldDir];
  const dx = actor.target.x - actor.x;
  const dy = actor.target.y - actor.y;
  if (Math.abs(dx) > 10 * FRACUNIT) {
    actor.moveDir = dx > 0 ? DI_EAST : DI_WEST;
  }
}
